// src/ScannerSection.js

import React, { useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { useQrScanner } from './useQrScanner';

// ── QR grid background ────────────────────────────────────────────────────────
const QrGridBackground = () => {
  const cells = Array.from({ length: 64 });
  return (
    <div
      aria-hidden="true"
      className="pointer-events-none absolute inset-0 overflow-hidden opacity-[0.03] dark:opacity-[0.06]"
    >
      <div
        className="absolute inset-0 grid grid-cols-8"
        style={{ gridTemplateRows: 'repeat(8, 1fr)' }}
      >
        {cells.map((_, i) => (
          <motion.div
            key={i}
            className="border border-purple-500"
            initial={{ opacity: 0 }}
            animate={{ opacity: [0, 1, 0] }}
            transition={{
              duration: 3 + (i % 4),
              repeat:   Infinity,
              delay:    (i * 0.08) % 3,
              ease:     'easeInOut',
            }}
          />
        ))}
      </div>
    </div>
  );
};

// ── Floating particle ─────────────────────────────────────────────────────────
const Particle = ({ style }) => (
  <motion.div
    className="absolute rounded-full bg-purple-400/20 dark:bg-purple-400/10 pointer-events-none"
    style={style}
    animate={{
      y:       [0, -30, 0],
      x:       [0, 10,  0],
      opacity: [0.2, 0.6, 0.2],
      scale:   [1, 1.2, 1],
    }}
    transition={{
      duration: style.duration,
      repeat:   Infinity,
      delay:    style.delay,
      ease:     'easeInOut',
    }}
  />
);

// ── Corner brackets ───────────────────────────────────────────────────────────
const ScannerCorners = () => (
  <div aria-hidden="true" className="absolute inset-0 pointer-events-none">
    <div className="absolute top-3 left-3 w-7 h-7 border-t-2 border-l-2 border-purple-500 rounded-tl-lg" />
    <div className="absolute top-3 right-3 w-7 h-7 border-t-2 border-r-2 border-purple-500 rounded-tr-lg" />
    <div className="absolute bottom-3 left-3 w-7 h-7 border-b-2 border-l-2 border-purple-500 rounded-bl-lg" />
    <div className="absolute bottom-3 right-3 w-7 h-7 border-b-2 border-r-2 border-purple-500 rounded-br-lg" />
  </div>
);

// ── Result card ───────────────────────────────────────────────────────────────
const ResultCard = ({ result, onCopy, onClear, copied }) => {
  const isUrl = result.startsWith('http://') || result.startsWith('https://');

  return (
    <motion.div
      initial={{ opacity: 0, y: 20, scale: 0.97 }}
      animate={{ opacity: 1, y: 0,  scale: 1    }}
      exit={{   opacity: 0, y: 10,  scale: 0.97 }}
      className="w-full bg-white dark:bg-[#1a1a2e] border border-gray-100 dark:border-purple-500/20 rounded-2xl p-5 shadow-lg"
    >
      <div className="flex items-center justify-between mb-3">
        <div className="flex items-center gap-2">
          <motion.div
            animate={{ scale: [1, 1.3, 1] }}
            transition={{ duration: 0.5 }}
            className="w-2 h-2 rounded-full bg-green-500"
          />
          <span className="text-sm font-semibold text-gray-700 dark:text-gray-200 uppercase tracking-wide">
            QR Decoded
          </span>
        </div>
        <button
          onClick={onClear}
          className="text-xs text-gray-400 hover:text-red-400 transition-colors duration-200 px-2 py-0.5 rounded-md hover:bg-red-50 dark:hover:bg-red-900/20"
        >
          Clear ✕
        </button>
      </div>

      <div className="bg-gray-50 dark:bg-[#0f0f1a] rounded-xl p-4 mb-4 break-all">
        <p className="text-sm text-gray-800 dark:text-gray-200 font-mono leading-relaxed">
          {result}
        </p>
      </div>

      <div className="flex gap-3">
        <motion.button
          whileHover={{ scale: 1.02 }}
          whileTap={{  scale: 0.98 }}
          onClick={onCopy}
          className="flex-1 py-2.5 rounded-xl bg-purple-600 hover:bg-purple-700 text-white text-sm font-semibold transition-colors duration-200"
        >
          {copied ? '✓ Copied!' : 'Copy Result'}
        </motion.button>

        {isUrl && (
          <motion.a
            whileHover={{ scale: 1.02 }}
            whileTap={{  scale: 0.98 }}
            href={result}
            target="_blank"
            rel="noopener noreferrer"
            className="flex-1 py-2.5 rounded-xl border border-purple-500/30 text-purple-600 dark:text-purple-400 text-sm font-semibold text-center hover:bg-purple-50 dark:hover:bg-purple-900/20 transition-colors duration-200"
          >
            Open URL ↗
          </motion.a>
        )}
      </div>
    </motion.div>
  );
};

// ── Main component ────────────────────────────────────────────────────────────
const ScannerSection = () => {
  const fileInputRef = useRef(null);
  const [copied, setCopied] = React.useState(false);

  const {
    isScanning,
    result,
    error,
    hasCamera,
    torchOn,
    videoRef,
    canvasRef,
    startScanning,
    stopScanning,
    toggleTorch,
    scanFromFile,
    setResult,
    setError,
  } = useQrScanner();

  const handleCopy = () => {
    navigator.clipboard.writeText(result).then(() => {
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    });
  };

  const handleClear = () => {
    setResult('');
    setError('');
  };

  const handleFileChange = (e) => {
    const file = e.target.files[0];
    if (file) scanFromFile(file);
    e.target.value = '';
  };

  const handleDrop = (e) => {
    e.preventDefault();
    const file = e.dataTransfer.files[0];
    if (file && file.type.startsWith('image/')) scanFromFile(file);
  };

  const handleDragOver = (e) => e.preventDefault();

  const particles = [
    { width: 8,  height: 8,  top: '10%', left: '5%',  duration: 4,   delay: 0   },
    { width: 12, height: 12, top: '20%', left: '88%', duration: 5,   delay: 0.5 },
    { width: 6,  height: 6,  top: '55%', left: '6%',  duration: 3.5, delay: 1   },
    { width: 10, height: 10, top: '75%', left: '92%', duration: 6,   delay: 1.5 },
    { width: 5,  height: 5,  top: '35%', left: '94%', duration: 4.5, delay: 0.8 },
    { width: 8,  height: 8,  top: '85%', left: '15%', duration: 5.5, delay: 2   },
  ];

  return (
    <motion.section
      id="scanner"
      aria-labelledby="scanner-heading"
      className="relative min-h-screen bg-white dark:bg-[#0f0f1a] transition-colors duration-500 px-6 md:px-16 lg:px-24 py-24 overflow-hidden"
      initial={{ opacity: 0, y: 60 }}
      whileInView={{ opacity: 1, y: 0 }}
      viewport={{ once: true, amount: 0.1 }}
      transition={{ duration: 0.7, ease: [0.25, 0.46, 0.45, 0.94] }}
    >
      {/* ── Background ── */}
      <QrGridBackground />
      <div aria-hidden="true" className="pointer-events-none absolute inset-0">
        {particles.map((p, i) => (
          <Particle key={i} style={p} />
        ))}
      </div>
      <div aria-hidden="true" className="pointer-events-none absolute inset-0 overflow-hidden">
        <motion.div
          animate={{ scale: [1, 1.15, 1], opacity: [0.06, 0.14, 0.06] }}
          transition={{ duration: 7, repeat: Infinity, ease: 'easeInOut' }}
          className="absolute -top-32 left-1/2 -translate-x-1/2 w-[700px] h-[700px] rounded-full bg-purple-500/10 dark:bg-purple-500/15 blur-[130px]"
        />
        <motion.div
          animate={{ scale: [1, 1.2, 1], opacity: [0.04, 0.10, 0.04] }}
          transition={{ duration: 9, repeat: Infinity, ease: 'easeInOut', delay: 2 }}
          className="absolute bottom-0 right-1/4 w-[500px] h-[500px] rounded-full bg-indigo-500/10 dark:bg-indigo-500/15 blur-[110px]"
        />
      </div>

      {/* ── Content ── */}
      <div className="relative z-10 max-w-4xl mx-auto">

        {/* Header */}
        <motion.div
          className="mb-14"
          initial={{ opacity: 0, y: 20 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
          transition={{ duration: 0.6 }}
        >
          <motion.p
            className="text-sm font-semibold uppercase tracking-widest text-purple-500 dark:text-purple-400 mb-2"
            initial={{ opacity: 0, x: -20 }}
            whileInView={{ opacity: 1, x: 0 }}
            viewport={{ once: true }}
            transition={{ duration: 0.5, delay: 0.1 }}
          >
            Scanner
          </motion.p>
          <h2
            id="scanner-heading"
            className="text-4xl md:text-5xl font-bold text-gray-900 dark:text-white tracking-tight"
          >
            Scan a QR Code
          </h2>
          <motion.div
            className="mt-1 h-1 w-16 bg-gradient-to-r from-purple-500 to-indigo-500 rounded-full"
            initial={{ scaleX: 0, originX: 0 }}
            whileInView={{ scaleX: 1 }}
            viewport={{ once: true }}
            transition={{ duration: 0.6, delay: 0.3 }}
          />
          <p className="mt-4 text-gray-500 dark:text-gray-400 text-base max-w-xl">
            Use your camera to scan a QR code instantly, or upload an image from your device.
          </p>
        </motion.div>

        {/* Main grid */}
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-10 lg:gap-16 items-start">

          {/* ── Camera panel ── */}
          <motion.div
            initial={{ opacity: 0, y: 30, filter: 'blur(6px)' }}
            whileInView={{ opacity: 1, y: 0, filter: 'blur(0px)' }}
            viewport={{ once: true }}
            transition={{ duration: 0.6, ease: [0.25, 0.46, 0.45, 0.94] }}
            className="flex flex-col gap-4"
          >
            {/* Viewfinder */}
            <div
              className="relative bg-gray-900 dark:bg-[#0a0a14] rounded-2xl overflow-hidden border border-gray-200 dark:border-purple-500/20"
              style={{ aspectRatio: '4/3' }}
              onDrop={handleDrop}
              onDragOver={handleDragOver}
            >
              {/* Video feed */}
              <video
                ref={videoRef}
                className="absolute inset-0 w-full h-full object-cover"
                muted
                playsInline
              />

              {/* Hidden canvas for scanning */}
              <canvas ref={canvasRef} className="hidden" />

              {/* Idle placeholder */}
              {!isScanning && (
                <div className="absolute inset-0 flex flex-col items-center justify-center gap-4 p-6">
                  <motion.div
                    animate={{ opacity: [0.3, 0.7, 0.3] }}
                    transition={{ duration: 2, repeat: Infinity }}
                    className="w-20 h-20 rounded-2xl border-2 border-dashed border-purple-500/40 flex items-center justify-center"
                  >
                    <span className="text-3xl">📷</span>
                  </motion.div>
                  <p className="text-sm text-gray-400 text-center">
                    Camera feed will appear here
                  </p>
                  <p className="text-xs text-gray-600 dark:text-gray-600 text-center">
                    Or drag and drop an image
                  </p>
                </div>
              )}

              {/* Scanning overlay */}
              {isScanning && (
                <>
                  <ScannerCorners />
                  {/* Animated scan line */}
                  <motion.div
                    className="absolute left-4 right-4 h-0.5 bg-gradient-to-r from-transparent via-purple-500 to-transparent shadow-lg"
                    style={{ boxShadow: '0 0 8px rgba(108,99,255,0.8)' }}
                    animate={{ top: ['15%', '85%', '15%'] }}
                    transition={{ duration: 2, repeat: Infinity, ease: 'easeInOut' }}
                  />
                  {/* Dim overlay with center cutout */}
                  <div className="absolute inset-0 bg-black/30" />
                  <div
                    className="absolute inset-0"
                    style={{
                      background: 'radial-gradient(ellipse 60% 55% at 50% 50%, transparent 0%, rgba(0,0,0,0.4) 100%)',
                    }}
                  />
                </>
              )}
            </div>

            {/* Camera controls */}
            <div className="flex gap-3">
              {!isScanning ? (
                <motion.button
                  whileHover={{ scale: 1.02, boxShadow: '0 8px 24px rgba(108,99,255,0.35)' }}
                  whileTap={{ scale: 0.98 }}
                  onClick={startScanning}
                  disabled={!hasCamera}
                  className="flex-1 py-3 rounded-xl bg-purple-600 hover:bg-purple-700 disabled:opacity-40 disabled:cursor-not-allowed text-white font-semibold text-sm transition-colors duration-200"
                >
                  {hasCamera ? '📷 Start Camera' : '📷 No Camera Found'}
                </motion.button>
              ) : (
                <>
                  <motion.button
                    whileHover={{ scale: 1.02 }}
                    whileTap={{ scale: 0.98 }}
                    onClick={stopScanning}
                    className="flex-1 py-3 rounded-xl bg-red-500 hover:bg-red-600 text-white font-semibold text-sm transition-colors duration-200"
                  >
                    ✕ Stop Camera
                  </motion.button>
                  <motion.button
                    whileHover={{ scale: 1.02 }}
                    whileTap={{ scale: 0.98 }}
                    onClick={toggleTorch}
                    className="px-4 py-3 rounded-xl border border-purple-500/30 text-purple-600 dark:text-purple-400 font-semibold text-sm hover:bg-purple-50 dark:hover:bg-purple-900/20 transition-colors duration-200"
                    title="Toggle flashlight"
                  >
                    {torchOn ? '🔦 On' : '💡 Off'}
                  </motion.button>
                </>
              )}
            </div>
          </motion.div>

          {/* ── Upload + Result panel ── */}
          <motion.div
            initial={{ opacity: 0, y: 30, filter: 'blur(6px)' }}
            whileInView={{ opacity: 1, y: 0, filter: 'blur(0px)' }}
            viewport={{ once: true }}
            transition={{ duration: 0.6, delay: 0.15, ease: [0.25, 0.46, 0.45, 0.94] }}
            className="flex flex-col gap-4"
          >
            {/* Upload card */}
            <motion.div
              whileHover={{ scale: 1.01, boxShadow: '0 12px 40px rgba(108,99,255,0.12)' }}
              onClick={() => fileInputRef.current?.click()}
              onDrop={handleDrop}
              onDragOver={handleDragOver}
              className="bg-white dark:bg-[#1a1a2e] border-2 border-dashed border-gray-200 dark:border-purple-500/20 hover:border-purple-400 dark:hover:border-purple-500/50 rounded-2xl p-8 text-center cursor-pointer transition-all duration-300 group"
            >
              <motion.div
                animate={{ y: [0, -6, 0] }}
                transition={{ duration: 2.5, repeat: Infinity, ease: 'easeInOut' }}
                className="text-4xl mb-3"
              >
                🖼️
              </motion.div>
              <p className="text-sm font-semibold text-gray-700 dark:text-gray-200 mb-1 group-hover:text-purple-600 dark:group-hover:text-purple-400 transition-colors duration-200">
                Upload an Image
              </p>
              <p className="text-xs text-gray-400 dark:text-gray-600">
                Click or drag and drop a PNG, JPG, GIF, or WEBP
              </p>
              <input
                ref={fileInputRef}
                type="file"
                accept="image/*"
                className="hidden"
                onChange={handleFileChange}
              />
            </motion.div>

            {/* Error message */}
            <AnimatePresence mode="wait">
              {error && (
                <motion.div
                  key="error"
                  initial={{ opacity: 0, y: 8,  scale: 0.98 }}
                  animate={{ opacity: 1, y: 0,  scale: 1    }}
                  exit={{   opacity: 0, y: -8, scale: 0.98  }}
                  className="bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-500/20 rounded-xl px-4 py-3"
                >
                  <p className="text-sm text-red-600 dark:text-red-400 text-center">
                    {error}
                  </p>
                </motion.div>
              )}
            </AnimatePresence>

            {/* Result card */}
            <AnimatePresence mode="wait">
              {result && (
                <ResultCard
                  key="result"
                  result={result}
                  onCopy={handleCopy}
                  onClear={handleClear}
                  copied={copied}
                />
              )}
            </AnimatePresence>

            {/* Empty state */}
            <AnimatePresence>
              {!result && !error && (
                <motion.div
                  initial={{ opacity: 0 }}
                  animate={{ opacity: 1 }}
                  exit={{   opacity: 0 }}
                  className="bg-purple-50 dark:bg-purple-900/10 border border-purple-100 dark:border-purple-500/10 rounded-xl p-4"
                >
                  <p className="text-xs font-semibold text-purple-600 dark:text-purple-400 uppercase tracking-wide mb-2">
                    ✦ How it works
                  </p>
                  <ul className="text-xs text-gray-500 dark:text-gray-400 space-y-1.5">
                    <li>📷 Click "Start Camera" and point at a QR code</li>
                    <li>🖼️ Or upload any image containing a QR code</li>
                    <li>⚡ Results appear instantly — no server involved</li>
                    <li>🔒 Everything stays on your device, 100% private</li>
                  </ul>
                </motion.div>
              )}
            </AnimatePresence>

          </motion.div>
        </div>
      </div>
    </motion.section>
  );
};

export default ScannerSection;