// src/useQrScanner.js

import { useState, useRef, useEffect, useCallback } from 'react';
import jsQR from 'jsqr';

// ── Reusable canvas for file scanning — avoids creating one per scan ──────────
const fileCanvas = document.createElement('canvas');
const fileCtx    = fileCanvas.getContext('2d');

export const useQrScanner = () => {
  const [isScanning, setIsScanning] = useState(false);
  const [result,     setResult]     = useState('');
  const [error,      setError]      = useState('');
  const [hasCamera,  setHasCamera]  = useState(false);
  const [torchOn,    setTorchOn]    = useState(false);

  const videoRef        = useRef(null);
  const canvasRef       = useRef(null);
  const streamRef       = useRef(null);
  const animFrameRef    = useRef(null);
  const trackRef        = useRef(null);
  const stopScanningRef = useRef(null);

  // ── Check camera availability ─────────────────────────────────────────────
  useEffect(() => {
    navigator.mediaDevices?.enumerateDevices().then((devices) => {
      setHasCamera(devices.some((d) => d.kind === 'videoinput'));
    });
  }, []);

  // ── Stop camera ───────────────────────────────────────────────────────────
  const stopScanning = useCallback(() => {
    if (animFrameRef.current) {
      cancelAnimationFrame(animFrameRef.current);
      animFrameRef.current = null;
    }
    if (streamRef.current) {
      streamRef.current.getTracks().forEach((t) => t.stop());
      streamRef.current = null;
    }
    if (videoRef.current) videoRef.current.srcObject = null;
    setIsScanning(false);
    setTorchOn(false);
  }, []);

  // Keep ref in sync so scanFrame can call it without being a dependency
  useEffect(() => {
    stopScanningRef.current = stopScanning;
  }, [stopScanning]);

  // ── Scan loop ─────────────────────────────────────────────────────────────
  const scanFrame = useCallback(() => {
    const video  = videoRef.current;
    const canvas = canvasRef.current;

    if (!video || !canvas || video.readyState !== video.HAVE_ENOUGH_DATA) {
      animFrameRef.current = requestAnimationFrame(scanFrame);
      return;
    }

    const ctx = canvas.getContext('2d');
    canvas.width  = video.videoWidth;
    canvas.height = video.videoHeight;
    ctx.drawImage(video, 0, 0, canvas.width, canvas.height);

    const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const code      = jsQR(imageData.data, imageData.width, imageData.height, {
      inversionAttempts: 'dontInvert',
    });

    if (code) {
      setResult(code.data);
      stopScanningRef.current?.();
      return;
    }

    animFrameRef.current = requestAnimationFrame(scanFrame);
  }, []);

  // ── Start camera ──────────────────────────────────────────────────────────
  const startScanning = useCallback(async () => {
    setError('');
    setResult('');

    try {
      const stream = await navigator.mediaDevices.getUserMedia({
        video: { facingMode: 'environment', width: { ideal: 1280 }, height: { ideal: 720 } },
      });
      streamRef.current = stream;

      const tracks = stream.getVideoTracks();
      if (tracks.length > 0) trackRef.current = tracks[0];

      if (videoRef.current) {
        videoRef.current.srcObject = stream;
        videoRef.current.setAttribute('playsinline', true);
        await videoRef.current.play();
      }

      setIsScanning(true);
      animFrameRef.current = requestAnimationFrame(scanFrame);
    } catch (err) {
      setError(
        err.name === 'NotAllowedError' ? 'Camera permission denied. Please allow camera access and try again.' :
        err.name === 'NotFoundError'   ? 'No camera found on this device.' :
        'Could not access camera. Please try uploading an image instead.'
      );
    }
  }, [scanFrame]);

  // ── Toggle torch ──────────────────────────────────────────────────────────
  const toggleTorch = useCallback(async () => {
    if (!trackRef.current) return;
    try {
      const newState = !torchOn;
      await trackRef.current.applyConstraints({ advanced: [{ torch: newState }] });
      setTorchOn(newState);
    } catch {}
  }, [torchOn]);

  // ── Scan from uploaded file ───────────────────────────────────────────────
  const scanFromFile = useCallback((file) => {
    if (!file) return;
    setError('');
    setResult('');

    const reader   = new FileReader();
    reader.onload  = (e) => {
      const img    = new Image();
      img.onload   = () => {
        // Reuse module-level canvas instead of creating one per scan
        fileCanvas.width  = img.width;
        fileCanvas.height = img.height;
        fileCtx.drawImage(img, 0, 0);
        const imageData = fileCtx.getImageData(0, 0, img.width, img.height);
        const code      = jsQR(imageData.data, imageData.width, imageData.height, {
          inversionAttempts: 'attemptBoth',
        });
        if (code) {
          setResult(code.data);
        } else {
          setError('No QR code found in this image. Please try a clearer photo.');
        }
      };
      img.src = e.target.result;
    };
    reader.readAsDataURL(file);
  }, []);

  // ── Cleanup on unmount ────────────────────────────────────────────────────
  useEffect(() => () => stopScanning(), [stopScanning]);

  return {
    isScanning, result, error, hasCamera, torchOn,
    videoRef, canvasRef,
    startScanning, stopScanning, toggleTorch, scanFromFile,
    setResult, setError,
  };
};